use itertools::Itertools;
use pixi_spec::ExcludeNewer;
use rattler_conda_types::NamedChannelOrUrl;
use toml_edit::{Table, Value};

/// A channel with an optional priority.
/// If the priority is not specified, it is assumed to be 0.
/// The higher the priority, the more important the channel is.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct PrioritizedChannel {
    pub channel: NamedChannelOrUrl,
    pub priority: Option<i32>,
    pub exclude_newer: Option<ExcludeNewer>,
}

impl PrioritizedChannel {
    /// The prioritized channels contain a priority, sort on this priority.
    /// Higher priority comes first. [-10, 1, 0 ,2] -> [2, 1, 0, -10]
    pub fn sort_channels_by_priority<'a, I>(
        channels: I,
    ) -> impl Iterator<Item = &'a NamedChannelOrUrl>
    where
        I: IntoIterator<Item = &'a crate::PrioritizedChannel>,
    {
        channels
            .into_iter()
            .sorted_by(|a, b| {
                let a = a.priority.unwrap_or(0);
                let b = b.priority.unwrap_or(0);
                b.cmp(&a)
            })
            .map(|prioritized_channel| &prioritized_channel.channel)
    }
}

impl From<NamedChannelOrUrl> for PrioritizedChannel {
    fn from(value: NamedChannelOrUrl) -> Self {
        Self {
            channel: value,
            priority: None,
            exclude_newer: None,
        }
    }
}

impl From<(NamedChannelOrUrl, Option<i32>)> for PrioritizedChannel {
    fn from((value, prio): (NamedChannelOrUrl, Option<i32>)) -> Self {
        Self {
            channel: value,
            priority: prio,
            exclude_newer: None,
        }
    }
}

impl From<PrioritizedChannel> for Value {
    fn from(channel: PrioritizedChannel) -> Self {
        match (channel.priority, channel.exclude_newer) {
            (Some(priority), exclude_newer) => {
                let mut table = Table::new().into_inline_table();
                table.insert("channel", channel.channel.to_string().into());
                table.insert("priority", i64::from(priority).into());
                if let Some(exclude_newer) = exclude_newer {
                    table.insert("exclude-newer", exclude_newer.to_string().into());
                }
                Value::InlineTable(table)
            }
            (None, Some(exclude_newer)) => {
                let mut table = Table::new().into_inline_table();
                table.insert("channel", channel.channel.to_string().into());
                table.insert("exclude-newer", exclude_newer.to_string().into());
                Value::InlineTable(table)
            }
            (None, None) => Value::String(toml_edit::Formatted::new(channel.channel.to_string())),
        }
    }
}

use std::collections::HashSet;

use chrono::{DateTime, Utc};
use indexmap::{IndexMap, IndexSet};
use itertools::Itertools;
use miette::Diagnostic;
use pixi_spec::{ExcludeNewer, ResolvedExcludeNewer};
use pixi_spec_containers::DependencyMap;
use rattler_conda_types::{
    ChannelConfig, ChannelUrl, NamedChannelOrUrl, ParseChannelError, Platform,
};

use crate::{
    CondaConstraints, CondaDependencies, PrioritizedChannel, PyPiDependencies, SpecType,
    SystemRequirements,
    dependencies::CondaDevDependencies,
    has_features_iter::HasFeaturesIter,
    has_manifest_ref::HasWorkspaceManifest,
    pypi::{ResolvedPypiExcludeNewer, pypi_options::PypiOptions},
    workspace::{ChannelPriority, SolveStrategy},
};

/// ChannelPriorityCombination error, thrown when multiple channel priorities
/// are set
#[derive(Debug, thiserror::Error, Diagnostic)]
#[error("Multiple channel priorities are not allowed in a single environment")]
pub struct ChannelPriorityCombinationError;

/// A trait that implement various methods for collections that combine
/// attributes of Features It is implemented by Environment, GroupedEnvironment
/// and SolveGroup. Remove some of the boilerplate of combining features and its
/// derived data from multiple sources.
///
/// The name of the lifetime parameter is named `'source` that the borrow comes
/// from the source of the data for most implementations this will be the pixi
/// project.
///
/// There is blanket implementation available for all types that implement
/// [`HasWorkspaceManifest`] and [`HasFeaturesIter`]
pub trait FeaturesExt<'source>: HasWorkspaceManifest<'source> + HasFeaturesIter<'source> {
    /// Returns the channels associated with this collection, preserving the
    /// effective metadata for the first winning entry of every unique channel.
    fn prioritized_channels(
        &self,
    ) -> IndexMap<&'source NamedChannelOrUrl, &'source PrioritizedChannel> {
        let channels = self.features().flat_map(|feature| match &feature.channels {
            Some(channels) => channels,
            None => &self.workspace_manifest().workspace.channels,
        });

        let mut prioritized = IndexMap::new();
        for channel in channels.into_iter().sorted_by(|a, b| {
            let a = a.priority.unwrap_or(0);
            let b = b.priority.unwrap_or(0);
            b.cmp(&a)
        }) {
            prioritized.entry(&channel.channel).or_insert(channel);
        }

        prioritized
    }

    /// Returns the channels associated with this collection.
    ///
    /// Users can specify custom channels on a per-feature basis. This method
    /// collects and deduplicates all the channels from all the features in
    /// the order they are defined in the manifest.
    ///
    /// If a feature does not specify any channel the default channels from the
    /// project metadata are used instead.
    fn channels(&self) -> IndexSet<&'source NamedChannelOrUrl> {
        self.prioritized_channels().into_keys().collect()
    }

    /// Returns the channels associated with this collection.
    ///
    /// This function is similar to [`Self::channels]` but it resolves the
    /// channel urls using the provided channel config.
    fn channel_urls(
        &self,
        channel_config: &ChannelConfig,
    ) -> Result<Vec<ChannelUrl>, ParseChannelError> {
        self.channels()
            .into_iter()
            .cloned()
            .map(|channel| channel.into_base_url(channel_config))
            .collect()
    }

    /// Returns the channel priority, error on multiple, different values, return None if
    /// no value is set.
    ///
    /// When using multiple channel priorities over different features we should
    /// error as the user should decide what they want.
    fn channel_priority(&self) -> Result<Option<ChannelPriority>, ChannelPriorityCombinationError> {
        let mut channel_priority = None;
        for feature in self.features() {
            if let Some(priority) = feature.channel_priority {
                // If we already have a priority and it's different, error
                if channel_priority.is_some() && channel_priority != Some(priority) {
                    return Err(ChannelPriorityCombinationError);
                }
                channel_priority = Some(priority);
            }
        }
        Ok(channel_priority)
    }

    /// Returns the raw workspace exclude-newer configuration before channel and
    /// package-specific overrides are applied.
    fn exclude_newer_raw(&self) -> Option<ExcludeNewer> {
        self.workspace_manifest().workspace.exclude_newer
    }

    /// Returns the effective exclude-newer solver configuration.
    fn exclude_newer_config(
        &self,
    ) -> Result<Option<rattler_solve::ExcludeNewer>, ParseChannelError> {
        self.exclude_newer_config_resolved()
            .map(|exclude_newer| exclude_newer.map(Into::into))
    }

    /// Returns the effective exclude-newer solver configuration with absolute cutoffs.
    fn exclude_newer_config_resolved(
        &self,
    ) -> Result<Option<ResolvedExcludeNewer>, ParseChannelError> {
        let mut exclude_newer = self
            .exclude_newer_raw()
            .map(|config| ResolvedExcludeNewer::from_datetime(config.cutoff()));

        for channel in self.prioritized_channels().into_values() {
            let Some(channel_exclude_newer) = channel.exclude_newer else {
                continue;
            };

            let config = exclude_newer.get_or_insert_with(|| {
                ResolvedExcludeNewer::from_datetime(DateTime::<Utc>::MAX_UTC)
            });

            *config = match channel_exclude_newer {
                ExcludeNewer::Timestamp(dt) => config
                    .clone()
                    .with_channel_cutoff(channel.channel.to_string(), dt),
                ExcludeNewer::Duration(duration) => config.clone().with_channel_cutoff(
                    channel.channel.to_string(),
                    ExcludeNewer::Duration(duration).cutoff(),
                ),
            };
        }

        for (name, package_exclude_newer) in &self
            .workspace_manifest()
            .workspace
            .exclude_newer_package_overrides
        {
            let config = exclude_newer.get_or_insert_with(|| {
                ResolvedExcludeNewer::from_datetime(DateTime::<Utc>::MAX_UTC)
            });

            *config = match package_exclude_newer {
                ExcludeNewer::Timestamp(dt) => {
                    config.clone().with_package_cutoff(name.clone(), *dt)
                }
                ExcludeNewer::Duration(duration) => config
                    .clone()
                    .with_package_cutoff(name.clone(), ExcludeNewer::Duration(*duration).cutoff()),
            };
        }

        Ok(exclude_newer)
    }

    /// Returns the effective PyPI exclude-newer solver configuration with absolute cutoffs.
    fn pypi_exclude_newer_config_resolved(&self) -> ResolvedPypiExcludeNewer {
        let mut exclude_newer = self
            .exclude_newer_raw()
            .map(|config| ResolvedPypiExcludeNewer::from_datetime(config.cutoff()))
            .unwrap_or_default();

        for (name, package_exclude_newer) in &self
            .workspace_manifest()
            .workspace
            .pypi_exclude_newer_package_overrides
        {
            exclude_newer = match package_exclude_newer {
                ExcludeNewer::Timestamp(dt) => {
                    exclude_newer.with_package_cutoff(name.as_normalized().clone(), *dt)
                }
                ExcludeNewer::Duration(duration) => exclude_newer.with_package_cutoff(
                    name.as_normalized().clone(),
                    ExcludeNewer::Duration(*duration).cutoff(),
                ),
            };
        }

        exclude_newer
    }

    /// Returns the strategy for solving packages.
    ///
    /// The chosen strategy is the first explicitly declared one in a feature
    /// as they are provided by the [`HasFeaturesIter::features`] iterator.
    ///
    /// If no feature declares a strategy, the default value of [`SolveStrategy`] is used.
    fn solve_strategy(&self) -> SolveStrategy {
        self.features()
            .flat_map(|feature| feature.solve_strategy)
            .next()
            .unwrap_or_default()
    }

    /// Returns the platforms that this collection is compatible with.
    ///
    /// Which platforms a collection support depends on which platforms the
    /// selected features of the collection supports. The platforms that are
    /// supported by the collection is the intersection of the platforms
    /// supported by its features.
    ///
    /// Features can specify which platforms they support through the
    /// `platforms` key. If a feature does not specify any platforms the
    /// features defined by the project are used.
    fn platforms(&self) -> HashSet<Platform> {
        self.features()
            .map(|feature| {
                match &feature.platforms {
                    Some(platforms) => platforms,
                    None => &self.workspace_manifest().workspace.platforms,
                }
                .iter()
                .copied()
                .collect::<HashSet<_>>()
            })
            .reduce(|accumulated_platforms, feat| {
                accumulated_platforms.intersection(&feat).copied().collect()
            })
            .unwrap_or_default()
    }

    /// Returns the system requirements for this collection.
    ///
    /// The system requirements of the collection are the union of the system
    /// requirements of all the features in the collection. If multiple
    /// features specify a requirement for the same system package, the
    /// highest is chosen.
    fn local_system_requirements(&self) -> SystemRequirements {
        self.features()
            .map(|feature| &feature.system_requirements)
            .fold(SystemRequirements::default(), |acc, req| {
                acc.union(req)
                    .expect("system requirements should have been validated upfront")
            })
    }

    /// Returns true if any of the features has any reference to a pypi
    /// dependency.
    fn has_pypi_dependencies(&self) -> bool {
        self.features().any(|f| f.has_pypi_dependencies())
    }

    /// Returns the PyPi dependencies to install for this collection.
    ///
    /// The dependencies of all features are combined. This means that if two
    /// features define a requirement for the same package that both
    /// requirements are returned. The different requirements per package
    /// are sorted in the same order as the features they came from.
    fn pypi_dependencies(&self, platform: Option<Platform>) -> PyPiDependencies {
        let deps: Vec<_> = self
            .features()
            .filter(|f| f.supports_platform(platform))
            .filter_map(|f| f.pypi_dependencies(platform))
            .collect();
        DependencyMap::merge_all(deps.iter().map(|d| d.as_ref()))
    }

    /// Returns the dependencies to install for this collection.
    ///
    /// The dependencies of all features are combined. This means that if two
    /// features define a requirement for the same package that both
    /// requirements are returned. The different requirements per package
    /// are sorted in the same order as the features they came from.
    ///
    /// If the `platform` is `None` no platform specific dependencies are taken
    /// into consideration.
    fn dependencies(&self, kind: SpecType, platform: Option<Platform>) -> CondaDependencies {
        let deps: Vec<_> = self
            .features()
            .filter(|f| f.supports_platform(platform))
            .filter_map(|f| f.dependencies(kind, platform))
            .collect();
        DependencyMap::merge_all(deps.iter().map(|d| d.as_ref()))
    }

    /// Returns the combined dependencies to install for this collection.
    ///
    /// The `build` dependencies overwrite the `host` dependencies which
    /// overwrite the `run` dependencies.
    ///
    /// The dependencies of all features are combined. This means that if two
    /// features define a requirement for the same package that both
    /// requirements are returned. The different requirements per package
    /// are sorted in the same order as the features they came from.
    ///
    /// If the `platform` is `None` no platform specific dependencies are taken
    /// into consideration.
    fn combined_dependencies(&self, platform: Option<Platform>) -> CondaDependencies {
        let deps: Vec<_> = self
            .features()
            .filter(|f| f.supports_platform(platform))
            .filter_map(|f| f.combined_dependencies(platform))
            .collect();
        DependencyMap::merge_all(deps.iter().map(|d| d.as_ref()))
    }

    /// Returns the combined dev dependencies to install for this collection.
    ///
    /// Dev dependencies from all features in the group are collected and
    /// merged. If multiple features define the same dev dependency, the
    /// last one wins (later features override earlier ones).
    fn combined_dev_dependencies(&self, platform: Option<Platform>) -> CondaDevDependencies {
        let deps: Vec<_> = self
            .features()
            .filter(|f| f.supports_platform(platform))
            .filter_map(|f| f.dev_dependencies(platform))
            .collect();

        DependencyMap::merge_all(deps.iter().map(|d| d.as_ref()))
    }

    /// Returns the combined version constraints for this collection.
    ///
    /// Constraints from all features are combined. If multiple features define
    /// a constraint for the same package, all constraints are retained and the
    /// solver must satisfy all of them simultaneously.
    ///
    /// If the `platform` is `None`, no platform specific constraints are taken
    /// into consideration.
    fn combined_constraints(&self, platform: Option<Platform>) -> CondaConstraints {
        let constraints: Vec<_> = self
            .features()
            .filter(|f| f.supports_platform(platform))
            .filter_map(|f| f.constraints(platform))
            .collect();
        DependencyMap::merge_all(constraints.iter().map(|d| d.as_ref()))
    }

    /// Returns the pypi options for this collection.
    ///
    /// The pypi options of all features are combined. They will be combined in
    /// the order that they are defined in the manifest.
    /// The index-url is a special case and can only be defined once. This
    /// should have been verified beforehand.
    fn pypi_options(&self) -> PypiOptions {
        // Collect all the pypi-options from the features in one set,
        // deduplicate them and sort them on feature index, default feature comes last.
        let pypi_options: Vec<_> = self
            .features()
            .filter_map(|feature| {
                if feature.pypi_options().is_none() {
                    self.workspace_manifest().workspace.pypi_options.as_ref()
                } else {
                    feature.pypi_options()
                }
            })
            .collect();

        // Merge all the pypi options into one.
        pypi_options
            .into_iter()
            .fold(PypiOptions::default(), |acc, opts| {
                acc.union(opts)
                    .expect("merging of pypi-options should already have been checked")
            })
    }
}

impl<'source, FeatureCollection> FeaturesExt<'source> for FeatureCollection where
    FeatureCollection: HasWorkspaceManifest<'source> + HasFeaturesIter<'source>
{
}

use std::{collections::HashMap, path::PathBuf};

use indexmap::{IndexMap, IndexSet};
use pixi_pypi_spec::PypiPackageName;
use pixi_spec::ExcludeNewer;
use pixi_toml::TomlEnum;
use rattler_conda_types::{NamedChannelOrUrl, PackageName, Platform, Version, VersionSpec};
use serde::Deserialize;
use toml_span::{DeserError, Value};
use url::Url;

use super::pypi::pypi_options::PypiOptions;
use crate::{PrioritizedChannel, S3Options, Targets, preview::Preview};
use minijinja::{AutoEscape, Environment, UndefinedBehavior};
use once_cell::sync::Lazy;

pub static JINJA_ENV: Lazy<Environment<'static>> = Lazy::new(|| {
    let mut env = Environment::new();
    env.set_undefined_behavior(UndefinedBehavior::Strict);
    env.set_auto_escape_callback(|_| AutoEscape::None);
    env
});

/// Describes the contents of the `[workspace]` section of the project manifest.
#[derive(Debug, Default, Clone)]
pub struct Workspace {
    /// The name of the project
    pub name: Option<String>,

    /// The version of the project
    pub version: Option<Version>,

    /// An optional project description
    pub description: Option<String>,

    /// Optional authors
    pub authors: Option<Vec<String>>,

    /// The channels used by the project
    pub channels: IndexSet<PrioritizedChannel>,

    /// Channel priority for the whole project
    pub channel_priority: Option<ChannelPriority>,

    /// Solve strategy for the whole project.
    pub solve_strategy: Option<SolveStrategy>,

    /// The platforms this project supports
    pub platforms: IndexSet<Platform>,

    /// The license as a valid SPDX string (e.g. MIT AND Apache-2.0)
    pub license: Option<String>,

    /// The license file (relative to the project root)
    pub license_file: Option<PathBuf>,

    /// Path to the README file of the project (relative to the project root)
    pub readme: Option<PathBuf>,

    /// URL of the project homepage
    pub homepage: Option<Url>,

    /// URL of the project source repository
    pub repository: Option<Url>,

    /// URL of the project documentation
    pub documentation: Option<Url>,

    /// URL or Path of the conda to pypi name mapping
    pub conda_pypi_map: Option<HashMap<NamedChannelOrUrl, String>>,

    /// The pypi options supported in the project
    pub pypi_options: Option<PypiOptions>,

    /// The S3 options supported in the project
    pub s3_options: Option<HashMap<String, S3Options>>,

    /// Preview features
    pub preview: Preview,

    /// Build variants defined directly in the manifest.
    pub build_variants: Targets<Option<HashMap<String, Vec<String>>>>,

    /// Ordered list of external variant configuration files.
    pub build_variant_files: Vec<BuildVariantSource>,

    /// Version requirement for pixi itself
    pub requires_pixi: Option<VersionSpec>,

    /// Exclude package candidates that are newer than this date.
    pub exclude_newer: Option<ExcludeNewer>,

    /// Workspace-wide conda package exclude-newer overrides.
    pub exclude_newer_package_overrides: IndexMap<PackageName, ExcludeNewer>,

    /// Workspace-wide PyPI package exclude-newer overrides.
    pub pypi_exclude_newer_package_overrides: IndexMap<PypiPackageName, ExcludeNewer>,
}

/// A source that contributes additional build variant definitions.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum BuildVariantSource {
    /// Load variants from a file relative to the workspace root.
    File(PathBuf),
}

#[derive(
    Debug,
    Copy,
    Clone,
    Default,
    Eq,
    PartialEq,
    strum::Display,
    strum::VariantNames,
    strum::EnumString,
    Deserialize,
)]
#[serde(rename_all = "kebab-case")]
#[strum(serialize_all = "kebab-case")]
pub enum ChannelPriority {
    #[default]
    Strict,
    Disabled,
}

impl<'de> toml_span::Deserialize<'de> for ChannelPriority {
    fn deserialize(value: &mut Value<'de>) -> Result<Self, DeserError> {
        TomlEnum::deserialize(value).map(TomlEnum::into_inner)
    }
}

impl From<ChannelPriority> for rattler_solve::ChannelPriority {
    fn from(value: ChannelPriority) -> Self {
        match value {
            ChannelPriority::Strict => rattler_solve::ChannelPriority::Strict,
            ChannelPriority::Disabled => rattler_solve::ChannelPriority::Disabled,
        }
    }
}

impl From<rattler_solve::ChannelPriority> for ChannelPriority {
    fn from(value: rattler_solve::ChannelPriority) -> Self {
        match value {
            rattler_solve::ChannelPriority::Strict => ChannelPriority::Strict,
            rattler_solve::ChannelPriority::Disabled => ChannelPriority::Disabled,
        }
    }
}

#[derive(
    Debug,
    Copy,
    Clone,
    Default,
    Eq,
    PartialEq,
    strum::Display,
    strum::VariantNames,
    strum::EnumString,
    Deserialize,
)]
#[serde(rename_all = "kebab-case")]
#[strum(serialize_all = "kebab-case")]
pub enum SolveStrategy {
    #[default]
    Highest,
    Lowest,
    LowestDirect,
}

impl<'de> toml_span::Deserialize<'de> for SolveStrategy {
    fn deserialize(value: &mut Value<'de>) -> Result<Self, DeserError> {
        TomlEnum::deserialize(value).map(TomlEnum::into_inner)
    }
}

impl From<SolveStrategy> for rattler_solve::SolveStrategy {
    fn from(value: SolveStrategy) -> Self {
        match value {
            SolveStrategy::Highest => rattler_solve::SolveStrategy::Highest,
            SolveStrategy::Lowest => rattler_solve::SolveStrategy::LowestVersion,
            SolveStrategy::LowestDirect => rattler_solve::SolveStrategy::LowestVersionDirect,
        }
    }
}

impl From<rattler_solve::SolveStrategy> for SolveStrategy {
    fn from(value: rattler_solve::SolveStrategy) -> Self {
        match value {
            rattler_solve::SolveStrategy::Highest => Self::Highest,
            rattler_solve::SolveStrategy::LowestVersion => Self::Lowest,
            rattler_solve::SolveStrategy::LowestVersionDirect => Self::LowestDirect,
        }
    }
}

use std::{
    collections::{HashMap, HashSet},
    path::PathBuf,
    sync::Arc,
};

use itertools::Itertools;
