#[rstest]
#[tokio::test]
#[traced_test]
async fn test_example_satisfiability(
    #[files("../../examples/**/p*.toml")] manifest_path: PathBuf,
) {
    // If a pyproject.toml is present check for `tool.pixi` in the file to avoid
    // testing of non-pixi files
    if manifest_path.file_name().unwrap() == "pyproject.toml" {
        let manifest_str = fs_err::read_to_string(&manifest_path).unwrap();
        if !manifest_str.contains("tool.pixi.workspace") {
            return;
        }
    }

    // If a pixi.toml is present check for `workspace` in the file to avoid
    // testing of non-pixi workspace files
    if manifest_path.file_name().unwrap() == "pixi.toml" {
        let manifest_str = fs_err::read_to_string(&manifest_path).unwrap();
        if !manifest_str.contains("workspace") {
            return;
        }
    }

    let project = Workspace::from_path(&manifest_path).unwrap();
    let lock_file = LockFile::from_path(&project.lock_file_path()).unwrap();
    match verify_lockfile_satisfiability(&project, &lock_file, None)
        .await
        .into_diagnostic()
    {
        Ok(()) => {}
        Err(e) => panic!("{e:?}"),
    }
}

#[rstest]
#[tokio::test]
#[traced_test]
async fn test_failing_satisfiability(
    #[files("../../tests/data/non-satisfiability/*/pixi.toml")] manifest_path: PathBuf,
) {
    let report_handler = NarratableReportHandler::new().with_cause_chain();

    let project = Workspace::from_path(&manifest_path).unwrap();
    let lock_file = LockFile::from_path(&project.lock_file_path()).unwrap();
    let err = verify_lockfile_satisfiability(
        &project,
        &lock_file,
        Some(BackendOverride::from_memory(
            PassthroughBackend::instantiator(),
        )),
    )
    .await
    .expect_err("expected failing satisfiability");

    let name = manifest_path
        .parent()
        .unwrap()
        .file_name()
        .and_then(OsStr::to_str)
        .unwrap();

    let mut s = String::new();
    report_handler.render_report(&mut s, &err).unwrap();

    let mut settings = Settings::clone_current();
    settings.set_snapshot_suffix(name);
    settings.bind(|| {
        // run snapshot test here
        insta::assert_snapshot!(s);
    });
}

#[test]
fn test_pypi_git_check_with_rev() {
    // Mock locked data
    let locked_data = PypiPackageData {
        name: "mypkg".parse().unwrap(),
        version: Version::from_str("0.1.0").unwrap(),
        location: "git+https://github.com/mypkg@rev=29932f3915935d773dc8d52c292cadd81c81071d#29932f3915935d773dc8d52c292cadd81c81071d"
            .parse()
            .expect("failed to parse url"),
        hash: None,
        requires_dist: vec![],
        requires_python: None,
        editable: false,
    };
    let spec = pep508_requirement_to_uv_requirement(
        pep508_rs::Requirement::from_str("mypkg @ git+https://github.com/mypkg@2993").unwrap(),
    )
    .unwrap();
    let project_root = PathBuf::from_str("/").unwrap();
    // This will not satisfy because the rev length is different, even being
    // resolved to the same one
    pypi_satisfies_requirement(&spec, &locked_data, &project_root).unwrap_err();

    let locked_data = PypiPackageData {
        name: "mypkg".parse().unwrap(),
        version: Version::from_str("0.1.0").unwrap(),
        location: "git+https://github.com/mypkg.git?rev=29932f3915935d773dc8d52c292cadd81c81071d#29932f3915935d773dc8d52c292cadd81c81071d"
            .parse()

    assert_eq!(
        foobar_channels
            .into_iter()
            .map(|c| c.to_string())
            .collect_vec(),
        vec!["nvidia", "pytorch", "barry", "conda-forge", "bar"]
    );
    let foo_channels = manifest.environment("foo").unwrap().channels();
    assert_eq!(
        foo_channels
            .into_iter()
            .map(|c| c.to_string())
            .collect_vec(),
        vec!["nvidia", "pytorch", "conda-forge"]
    );

    let bar_channels = manifest.environment("bar").unwrap().channels();
    assert_eq!(
        bar_channels
            .into_iter()
            .map(|c| c.to_string())
            .collect_vec(),
        vec!["barry", "conda-forge", "bar"]
    );
}

#[test]
fn test_channel_specific_exclude_newer_across_multiple_features() {
    let workspace = Workspace::from_str(
        Path::new("pixi.toml"),
        r#"
    [project]
    name = "test"
    channels = ["conda-forge"]
    platforms = ["linux-64"]
    exclude-newer = "2015-12-02T02:07:43Z"

    [feature.foo]
    channels = [
        { channel = "bioconda", exclude-newer = "2016-12-02T02:07:43Z" },
        { channel = "pytorch", exclude-newer = "2017-12-02T02:07:43Z" },
    ]

    [feature.bar]
    channels = [
        { channel = "nvidia", exclude-newer = "2018-12-02T02:07:43Z" },
        { channel = "dglteam", exclude-newer = "2019-12-02T02:07:43Z" },
    ]

    [environments]
    combined = ["foo", "bar"]
    "#,
    )
    .unwrap();

    let env = workspace.environment("combined").unwrap();
    let config = env.exclude_newer_config().unwrap().unwrap();
    let package = PackageName::new_unchecked("polars");

    assert_eq!(
        config.cutoff_for_package(&package, Some("bioconda")),
        chrono::DateTime::parse_from_rfc3339("2016-12-02T02:07:43Z")
            .unwrap()
            .with_timezone(&chrono::Utc)
    );
    assert_eq!(
        config.cutoff_for_package(&package, Some("pytorch")),
        chrono::DateTime::parse_from_rfc3339("2017-12-02T02:07:43Z")
            .unwrap()
            .with_timezone(&chrono::Utc)
    );
    assert_eq!(
        config.cutoff_for_package(&package, Some("nvidia")),
        chrono::DateTime::parse_from_rfc3339("2018-12-02T02:07:43Z")
            .unwrap()
            .with_timezone(&chrono::Utc)
    );
    assert_eq!(
        config.cutoff_for_package(&package, Some("dglteam")),
        chrono::DateTime::parse_from_rfc3339("2019-12-02T02:07:43Z")
            .unwrap()
            .with_timezone(&chrono::Utc)
    );
    assert_eq!(
        config.cutoff_for_package(&package, Some("conda-forge")),
        chrono::DateTime::parse_from_rfc3339("2015-12-02T02:07:43Z")
            .unwrap()
            .with_timezone(&chrono::Utc)
    );
}

