fn test_channel_specific_exclude_newer_uses_resolved_channel_url() {
    let workspace = Workspace::from_str(
        Path::new("pixi.toml"),
        r#"
    [workspace]
    name = "test"
    channels = [
        { channel = "conda-forge", exclude-newer = "2016-12-02T02:07:43Z" },
        { channel = "https://prefix.dev/github-releases", exclude-newer = "2017-12-02T02:07:43Z" },
    ]
    platforms = ["linux-64"]
    exclude-newer = "2015-12-02T02:07:43Z"

    [dependencies]
    chainsaw = "*"
    "#,
    )
    .unwrap();

    let env = workspace.environment("default").unwrap();
    let config = env.exclude_newer_config().unwrap().unwrap();
    let package = PackageName::new_unchecked("chainsaw");
    let workspace_cutoff = chrono::DateTime::parse_from_rfc3339("2015-12-02T02:07:43Z")
        .unwrap()
        .with_timezone(&chrono::Utc);
    let conda_forge_cutoff = chrono::DateTime::parse_from_rfc3339("2016-12-02T02:07:43Z")
        .unwrap()
        .with_timezone(&chrono::Utc);
    let github_releases_cutoff =
        chrono::DateTime::parse_from_rfc3339("2017-12-02T02:07:43Z")
            .unwrap()
            .with_timezone(&chrono::Utc);

    assert_eq!(
        config.cutoff_for_package(&package, Some("conda-forge")),
        conda_forge_cutoff
    );
    assert_eq!(
        config.cutoff_for_package(&package, Some("https://conda.anaconda.org/conda-forge/")),
        conda_forge_cutoff
    );
    assert_eq!(
        config.cutoff_for_package(&package, Some("https://prefix.dev/github-releases/")),
        github_releases_cutoff
    );
    assert_eq!(
        config.cutoff_for_package(&package, Some("https://example.com/unknown/")),
        workspace_cutoff
    );
}

