                    channel: NamedChannelOrUrl::Name(String::from("test")),
                    priority: None,
                    exclude_newer: None,
                },
                PrioritizedChannel {
                    channel: NamedChannelOrUrl::Name(String::from("test2")),
                    priority: None,
                    exclude_newer: None,
                },
            ]
            .into_iter()
            .collect::<IndexSet<_>>()
        );

